import java.util.*;

public int maxEvents(int[][] events) {
    Arrays.sort(events, (a, b) -> a[0] - b[0]);
    PriorityQueue<Integer> minHeap = new PriorityQueue<>();
    int eventCount = 0, day = 0;

    for (int[] event : events) {
        while (!minHeap.isEmpty() && minHeap.peek() < event[0]) {
            minHeap.poll();
        }
        minHeap.add(event[1]);
        eventCount++;
        day++;
    }

    return eventCount;
}
```


